/**
 * Send email using configured transporter
 * @param {Object} emailOptions - Email options (to, subject, html, etc.)
 * @returns {Promise} Send email promise
 */
const sendEmail = async (emailOptions) => {
  try {
    // For development, just log emails instead of sending
    if (process.env.NODE_ENV === 'development') {
      console.log('\n📧 ===== EMAIL SIMULATION =====');
      console.log('📤 TO:', emailOptions.to);
      console.log('📋 SUBJECT:', emailOptions.subject);
      console.log('📝 HTML CONTENT:');
      console.log(emailOptions.html?.substring(0, 500) + '...' || 'No HTML content');
      console.log('===============================\n');
      
      return { 
        messageId: 'simulated-' + Date.now(),
        response: 'Email logged to console (development mode)' 
      };
    }

    const transporter = createTransporter();
    
    const mailOptions = {
      from: process.env.EMAIL_FROM || process.env.EMAIL_USER,
      to: emailOptions.to,
      subject: emailOptions.subject,
      html: emailOptions.html,
      text: emailOptions.text,
      ...emailOptions
    };

    const result = await transporter.sendMail(mailOptions);
    console.log('✅ Email sent successfully:', result.messageId);
    return result;
  } catch (error) {
    console.error('❌ Email sending failed:', error.message);
    throw error;
  }
};

/**
 * Test email configuration
 * @returns {Promise} Test result
 */
const testEmailConfig = async () => {
  try {
    const transporter = createTransporter();
    await transporter.verify();
    console.log('✅ Email configuration is valid');
    return true;
  } catch (error) {
    console.error('❌ Email configuration test failed:', error.message);
    return false;
  }
};

module.exports = {
  createTransporter,
  emailTemplates,
  sendEmail,
  testEmailConfig
};
